const a=document.querySelectorAll("#who"),c=document.querySelectorAll("#spend"),r=document.querySelectorAll("#admin-link"),d=document.querySelectorAll("#logout"),u=document.querySelectorAll("[data-user-name]"),f=document.querySelectorAll("[data-user-initials]");function h(t){const n=t.email||"",o=(t.name||"").trim(),l=n.split("@")[0]||n,e=o||l;let i;if(o){const s=o.split(/\s+/).filter(Boolean);i=s.length>=2?s[0][0]+s[1][0]:o.slice(0,2)}else i=l.replace(/[^a-z0-9]/gi,"").slice(0,2)||n.slice(0,2);return{display:e,initials:(i||"?").toUpperCase()}}function p(t){a.forEach(e=>{e.textContent=t.email});const{display:n,initials:o}=h(t);u.forEach(e=>{e.textContent=n}),f.forEach(e=>{e.textContent=o});let l="";if(typeof t.spent_usd=="number"){const e="$"+t.spent_usd.toFixed(2);l=t.unlimited?e+" today":e+" / $"+Number(t.budget_usd).toFixed(2)+" today"}c.forEach(e=>{e.textContent=l}),t.is_admin&&r.forEach(e=>{e.hidden=!1})}async function y(){try{const t=await fetch("/api/auth/me");if(!t.ok)return window.location.href="/login",null;const n=await t.json();return p(n),n}catch{return window.location.href="/login",null}}d.forEach(t=>{t.addEventListener("click",async()=>{try{await fetch("/api/auth/logout",{method:"POST"})}finally{window.location.href="/login"}})});y();export{y as r};
